import type { CareerQuestion } from "./rrt-questions";

export const rrtDomainQuestionsBatch6: CareerQuestion[] = [
  { id: "rrt-mv-062", stem: "A patient on PSV 12 cmH2O has an exhaled Vt of 650 mL, which is higher than the target of 6 mL/kg IBW (420 mL). What adjustment should be made?", options: ["Decrease pressure support level to reduce delivered tidal volume", "Increase pressure support to provide more assistance", "No adjustment needed — larger Vt is always better", "Switch to volume control ventilation"], correctIndex: 0, rationale: "In PSV, the patient determines their own Vt based on effort and the PS level. If Vt is excessively large, reduce the PS level to decrease the amount of augmentation. Excessively large Vt can cause volutrauma, especially in ARDS patients. Target 6-8 mL/kg IBW even in spontaneous modes.", difficulty: 2, category: "Mechanical Ventilation", topic: "Weaning Protocols", questionType: "case-based", examTip: "PSV: reduce PS level to decrease Vt. Even in spontaneous modes, avoid excessive Vt (target 6-8 mL/kg)." },
  { id: "rrt-mv-063", stem: "What is the 'DOPE' mnemonic used for when troubleshooting acute deterioration in a ventilated patient?", options: ["Displacement (ETT), Obstruction (secretions/kink), Pneumothorax, Equipment failure", "Drugs, Oxygen, Position, Electricity", "Diagnosis, Outcome, Prognosis, Evaluation", "Documentation, Orders, Plan, Execution"], correctIndex: 0, rationale: "DOPE: D = Displacement (ETT dislodged or in right main-stem), O = Obstruction (secretions, mucus plug, kinked tube, biting), P = Pneumothorax (especially tension), E = Equipment failure (ventilator malfunction, circuit disconnect, O2 source failure). When acute deterioration occurs: disconnect from ventilator, manually bag with 100% O2, and systematically evaluate DOPE.", difficulty: 2, category: "Mechanical Ventilation", topic: "Ventilator Troubleshooting", questionType: "multiple-choice", examTip: "DOPE: Displacement, Obstruction, Pneumothorax, Equipment. Acute deterioration: disconnect, bag, evaluate DOPE." },
  { id: "rrt-mv-064", stem: "A ventilated patient has a Pplat of 32 cmH2O on Vt 500 mL (7 mL/kg IBW) and PEEP 10. The physician wants to maintain current settings. What is the risk?", options: ["Ventilator-induced lung injury (VILI) from elevated Pplat exceeding the safe threshold of 30 cmH2O", "No risk — Pplat of 32 is normal", "Risk of under-ventilation only", "Equipment damage from high pressures"], correctIndex: 0, rationale: "Pplat > 30 cmH2O is associated with alveolar overdistension and ventilator-induced lung injury (VILI). Mechanisms: volutrauma (overdistension), barotrauma (high pressure), biotrauma (inflammatory mediator release). Reducing Vt to 6 mL/kg (430 mL) would likely bring Pplat below 30. The RT should recommend this adjustment.", difficulty: 3, category: "Mechanical Ventilation", topic: "ARDS Ventilation Strategy", questionType: "case-based", examTip: "Pplat > 30 = VILI risk. Reduce Vt first (down to 4 mL/kg if needed). Advocate for lung-protective settings." },
  { id: "rrt-mv-065", stem: "What is the role of esophageal pressure monitoring in mechanical ventilation?", options: ["Estimates pleural pressure to calculate transpulmonary pressure, guiding PEEP optimization in ARDS", "Monitors swallowing function", "Measures gastric pH", "Assesses esophageal reflux"], correctIndex: 0, rationale: "Esophageal pressure (Pes) monitoring uses a balloon catheter to estimate pleural pressure. Transpulmonary pressure (PL) = airway pressure - Pes. This helps differentiate lung vs chest wall contributions to total respiratory system mechanics, guiding PEEP titration (target end-expiratory PL > 0 to prevent collapse, end-inspiratory PL < 20-25 to prevent overdistension).", difficulty: 5, category: "Mechanical Ventilation", topic: "Waveform Analysis", questionType: "multiple-choice", examTip: "Esophageal pressure → transpulmonary pressure → PEEP optimization. End-exp PL > 0, end-insp PL < 20-25." },
  { id: "rrt-mv-066", stem: "What is the difference between static and dynamic compliance in mechanical ventilation?", options: ["Static uses Pplat (no-flow); dynamic uses PIP (includes resistance). Static isolates lung/chest wall compliance; dynamic reflects both compliance and resistance.", "They are identical measurements", "Dynamic is always lower than static in healthy lungs", "Static compliance includes airway resistance"], correctIndex: 0, rationale: "Static compliance (Cst) = Vt/(Pplat-PEEP): measured with no flow (inspiratory hold), reflects true lung/chest wall distensibility. Dynamic compliance (Cdyn) = Vt/(PIP-PEEP): measured during gas flow, includes both compliance AND resistance effects. Cdyn < Cst always. If Cst decreases: compliance problem (ARDS, edema). If Cdyn decreases with stable Cst: resistance problem (bronchospasm).", difficulty: 3, category: "Mechanical Ventilation", topic: "Ventilator Calculations", questionType: "multiple-choice", examTip: "Cst = compliance only (Pplat). Cdyn = compliance + resistance (PIP). Compare both to identify the problem." },
  { id: "rrt-abg-039", stem: "A patient receiving high-dose loop diuretics for CHF has ABG: pH 7.52, PaCO2 44, HCO3 35. What type of metabolic alkalosis is this?", options: ["Contraction (chloride-responsive) metabolic alkalosis from diuretic-induced volume depletion", "Expansion metabolic alkalosis", "Respiratory alkalosis", "Normal response to diuretics"], correctIndex: 0, rationale: "Loop diuretics cause: (1) Volume depletion (contraction), (2) Chloride loss in urine, (3) Increased bicarbonate reabsorption (contraction alkalosis). Urine Cl- < 20 mEq/L confirms chloride-responsive (contraction) alkalosis. Treatment: IV normal saline (replaces volume and Cl-), potassium repletion, and consider acetazolamide. Chloride-resistant alkalosis (urine Cl- > 20) has different causes.", difficulty: 4, category: "ABG Interpretation", topic: "Compensation Mechanisms", questionType: "case-based", examTip: "Diuretic-induced met alkalosis: contraction type, Cl-responsive (urine Cl < 20). Treat with NS + KCl." },
  { id: "rrt-abg-040", stem: "What are the ABG findings consistent with chronic metabolic acidosis (e.g., in chronic kidney disease)?", options: ["Mild acidosis with low HCO3, partially compensated by chronically low PaCO2, pH approaching but not reaching normal", "Normal pH with normal HCO3 and PaCO2", "Severe acidosis with no compensation", "Normal ABG values"], correctIndex: 0, rationale: "Chronic metabolic acidosis (CKD, RTA): mild-moderate pH depression (7.30-7.38), chronically low HCO3 (14-20), chronically low PaCO2 (respiratory compensation). The pH approaches but doesn't fully normalize. Compensation is appropriate per Winter's formula. CKD patients often have stable compensated metabolic acidosis as their baseline.", difficulty: 3, category: "ABG Interpretation", topic: "Compensation Mechanisms", questionType: "multiple-choice", examTip: "Chronic met acidosis: stable mild acidosis, low HCO3, low PaCO2 (compensated). CKD patients: this is their baseline." },
  { id: "rrt-o2-028", stem: "What is the air-oxygen blender and where is it used?", options: ["Device that mixes compressed air and oxygen to deliver precise FiO2 (0.21-1.0); used in NICUs, ventilators, and HFNC systems", "A type of face mask", "Standard oxygen regulator", "Room air purification system"], correctIndex: 0, rationale: "An air-oxygen blender mixes compressed air (21% O2) with compressed oxygen (100% O2) to deliver any desired FiO2 from 0.21 to 1.0. It requires both 50 psi air and 50 psi oxygen sources. Essential in NICUs (precise FiO2 control for preterm infants), ventilator circuits, and some HFNC setups. If one gas source fails, most blenders have an alarm system.", difficulty: 2, category: "Oxygen Therapy", topic: "Delivery Devices", questionType: "multiple-choice", examTip: "Air-O2 blender: precise FiO2 from 0.21-1.0. Needs 50 psi air + 50 psi O2. Critical in NICU." },
  { id: "rrt-o2-029", stem: "A COPD patient on home O2 via nasal cannula at 2 L/min wants to travel by airplane. The cabin altitude equivalent is typically 6,000-8,000 feet. What should be recommended?", options: ["Perform a hypoxia altitude simulation test (HAST) to determine in-flight O2 needs; typically increase flow by 1-2 L/min during flight", "Discontinue oxygen during the flight", "No adjustment needed — cabin pressure doesn't affect oxygenation", "The patient cannot fly with supplemental oxygen"], correctIndex: 0, rationale: "Commercial aircraft cabins pressurize to 6,000-8,000 ft equivalent (PB ~565-630 mmHg), reducing PAO2 significantly. COPD patients on home O2 need assessment: HAST (hypoxia altitude simulation test) breathes 15% FiO2 to simulate altitude — if PaO2 drops < 50, in-flight O2 is needed. General rule: increase flow by 1-2 L/min above baseline. Arrange portable oxygen concentrator (POC).", difficulty: 3, category: "Oxygen Therapy", topic: "Titration Protocols", questionType: "case-based", examTip: "COPD air travel: HAST test recommended. Generally increase O2 by 1-2 L/min. Use portable O2 concentrator." },
  { id: "rrt-aw-027", stem: "What is a supraglottic airway (SGA) and when is it used?", options: ["Airway device placed above the glottis (e.g., LMA, i-gel) for rescue airway or when intubation is not possible", "Device inserted below the vocal cords", "Nasal airway only", "Standard face mask"], correctIndex: 0, rationale: "Supraglottic airways (LMA, i-gel, King LT) are placed above the glottis without entering the trachea. Uses: (1) Rescue airway when intubation fails, (2) CPR airway management, (3) Brief anesthesia cases, (4) Pre-hospital airway. Advantages: faster placement than ETT, no laryngoscopy needed. Limitations: does not protect against aspiration, limited for prolonged ventilation.", difficulty: 2, category: "Airway Management", topic: "Airway Assessment", questionType: "multiple-choice", examTip: "SGA (LMA, i-gel): above glottis, rescue airway, CPR. Faster than ETT but doesn't protect against aspiration." },
  { id: "rrt-aw-028", stem: "What is the recommended humidification for a patient with a tracheostomy breathing room air?", options: ["Heated humidity or HME to provide 30-44 mg/L absolute humidity — the upper airway humidification is bypassed", "No humidification needed", "Cold aerosol only", "Nasal cannula provides adequate humidification"], correctIndex: 0, rationale: "A tracheostomy bypasses the normal humidification function of the nose and upper airways (which normally provide 30-44 mg/L absolute humidity at 37°C). Without adequate humidification, patients develop thick secretions, mucosal drying, airway crusting, and impaired mucociliary clearance. Options: heated humidifier (preferred for continuous use) or HME (for mobile patients, if secretions are manageable).", difficulty: 2, category: "Airway Management", topic: "Tracheostomy Care", questionType: "multiple-choice", examTip: "Tracheostomy bypasses upper airway humidification. Must provide 30-44 mg/L humidity. Heated humidifier or HME." },
  { id: "rrt-pft-020", stem: "What measurements can be obtained from a cardiopulmonary exercise test (CPET)?", options: ["VO2max, anaerobic threshold, VE/VCO2 slope, exercise capacity, cardiac and ventilatory reserve", "Only spirometry values", "Only blood pressure", "Only oxygen saturation"], correctIndex: 0, rationale: "CPET provides comprehensive assessment: VO2max/peak (maximal oxygen consumption), anaerobic threshold (AT), VE/VCO2 slope (ventilatory efficiency), dead space ventilation (VD/VT), oxygen pulse (VO2/HR), cardiac and ventilatory reserves, exercise-induced desaturation, and exercise-induced bronchospasm. Used for surgical risk, dyspnea evaluation, pulmonary hypertension assessment, and disability evaluation.", difficulty: 4, category: "Pulmonary Function Testing", topic: "Exercise Testing", questionType: "multiple-choice", examTip: "CPET: VO2max, anaerobic threshold, VE/VCO2. Comprehensive cardiac-pulmonary-metabolic assessment." },
  { id: "rrt-pft-021", stem: "A patient's spirometry shows FEV1 42%, FVC 80%, FEV1/FVC 0.52. Post-bronchodilator: FEV1 44%, FVC 82%. What is the interpretation?", options: ["Severe obstructive disease with poor bronchodilator reversibility consistent with COPD", "Mild restrictive disease", "Normal spirometry with good response", "Mixed obstructive-restrictive pattern"], correctIndex: 0, rationale: "FEV1/FVC 0.52 (< 0.70) confirms obstruction. FEV1 42% predicted = severe obstruction (GOLD classification: Mild ≥ 80%, Moderate 50-79%, Severe 30-49%, Very Severe < 30%). Post-bronchodilator improvement of only 2% and < 200 mL does NOT meet reversibility criteria (≥ 12% AND ≥ 200 mL), consistent with COPD rather than asthma.", difficulty: 3, category: "Pulmonary Function Testing", topic: "Spirometry", questionType: "case-based", examTip: "GOLD obstruction severity: Mild ≥ 80%, Moderate 50-79%, Severe 30-49%, Very Severe < 30% FEV1." },
  { id: "rrt-neo-031", stem: "What is the recommended surfactant replacement therapy approach for extremely preterm infants (< 28 weeks)?", options: ["Early rescue surfactant via INSURE or LISA technique combined with early CPAP", "Prophylactic surfactant for all preterm infants regardless of respiratory status", "Surfactant only after intubation for > 24 hours", "No surfactant — use CPAP alone for all preterm infants"], correctIndex: 0, rationale: "Current evidence favors early rescue surfactant (given when RDS is diagnosed, not prophylactically) combined with early nasal CPAP. INSURE (Intubate-Surfactant-Extubate) or LISA (Less Invasive Surfactant Administration via thin catheter without intubation) are preferred to minimize ventilator exposure. Multiple doses may be needed (up to 3-4). Early CPAP reduces BPD.", difficulty: 3, category: "Neonatal & Pediatric Respiratory Care", topic: "Surfactant Therapy", questionType: "multiple-choice", examTip: "Extremely preterm: early rescue surfactant (INSURE/LISA) + CPAP. Not prophylactic. Minimize ventilator time." },
  { id: "rrt-neo-032", stem: "A 4-year-old child with epiglottitis is in the emergency department. The child is sitting upright, drooling, and has a high fever. What should the respiratory therapist NOT do?", options: ["Do NOT examine the throat or attempt to visualize the epiglottis — may trigger complete airway obstruction", "Prepare emergency airway equipment", "Notify anesthesiology and ENT", "Administer humidified oxygen via blow-by"], correctIndex: 0, rationale: "In suspected epiglottitis: NEVER examine the throat, depress the tongue, or attempt direct visualization — this can cause laryngospasm and complete airway obstruction. Keep the child calm, in a position of comfort (usually sitting upright), and proceed to the OR with ENT and anesthesiology for controlled intubation or tracheostomy. Have emergency airway equipment ready.", difficulty: 3, category: "Neonatal & Pediatric Respiratory Care", topic: "Croup and Epiglottitis", questionType: "case-based", examTip: "Epiglottitis: NEVER examine throat. Keep child calm. OR for controlled intubation. Have tracheostomy backup." },
  { id: "rrt-cc-030", stem: "What is the difference between SIMV and AC (Assist/Control) modes?", options: ["AC delivers full support with every breath (mandatory or patient-triggered). SIMV delivers set mandatory breaths and allows unsupported or PS-augmented spontaneous breaths between.", "They are identical modes", "SIMV provides more support than AC", "AC only delivers time-triggered breaths"], correctIndex: 0, rationale: "AC: every breath (whether ventilator or patient-triggered) receives full Vt/pressure support. Total RR = set RR + patient-triggered breaths, all fully supported. SIMV: only the set mandatory breaths receive full support. Spontaneous breaths between mandatory breaths are either unsupported or augmented with pressure support (if added). SIMV was historically used for weaning but AC + daily SBT is now preferred.", difficulty: 2, category: "Critical Care Respiratory Therapy", topic: "ARDS Management", questionType: "multiple-choice", examTip: "AC: every breath fully supported. SIMV: mandatory breaths supported, spontaneous may not be. AC + SBT preferred for weaning." },
  { id: "rrt-cc-031", stem: "What are the indications for therapeutic hypothermia (targeted temperature management) in post-cardiac arrest patients?", options: ["Comatose adult survivors of cardiac arrest (especially VF/pVT); target 32-36°C for at least 24 hours", "All cardiac arrest patients regardless of consciousness", "Only for hypothermic drowning victims", "Contraindicated in post-arrest patients"], correctIndex: 0, rationale: "Targeted temperature management (TTM) is recommended for comatose adult survivors of cardiac arrest (both shockable and non-shockable rhythms per 2020 AHA guidelines). Target: 32-36°C for ≥ 24 hours. Benefits: neuroprotection, reduced cerebral metabolic demand, decreased reperfusion injury. Actively prevent fever (> 37.5°C) for at least 72 hours post-arrest.", difficulty: 3, category: "Critical Care Respiratory Therapy", topic: "Multi-Organ Failure", questionType: "multiple-choice", examTip: "TTM post-arrest: comatose survivors, 32-36°C for ≥ 24 hours. Prevent fever for 72 hours. Neuroprotection." },
  { id: "rrt-cp-029", stem: "What is the relationship between PaCO2 and alveolar ventilation?", options: ["Inversely proportional — doubling VA halves PaCO2; halving VA doubles PaCO2", "Directly proportional — more VA means higher PaCO2", "No relationship exists", "PaCO2 only depends on FiO2"], correctIndex: 0, rationale: "PaCO2 is inversely proportional to alveolar ventilation: PaCO2 = (VCO2 × 0.863) / VA. If VA doubles, PaCO2 halves. If VA halves, PaCO2 doubles. This is a fundamental gas exchange principle. To lower PaCO2 on a ventilator: increase RR or Vt (increase VA). To raise PaCO2 (e.g., respiratory alkalosis): decrease RR or Vt.", difficulty: 2, category: "Cardiopulmonary Physiology", topic: "Gas Exchange Physiology", questionType: "multiple-choice", examTip: "PaCO2 ∝ 1/VA. Double VA → halve PaCO2. To lower CO2: increase RR or Vt." },
  { id: "rrt-cp-030", stem: "What is the normal pulmonary capillary transit time and its clinical significance?", options: ["Approximately 0.75 seconds at rest; blood is fully oxygenated in 0.25 seconds, providing a 0.50 second reserve", "10 seconds, no reserve", "0.1 seconds with no time for gas exchange", "5 seconds, fully utilized for gas exchange"], correctIndex: 0, rationale: "Normal pulmonary capillary transit time is approximately 0.75 seconds. Blood is fully oxygenated within the first 0.25 seconds (1/3 of transit time), leaving a 0.50-second reserve. This reserve is important during exercise (when CO increases and transit time shortens) and in disease states with thickened alveolar-capillary membranes (ILD) where diffusion takes longer.", difficulty: 4, category: "Cardiopulmonary Physiology", topic: "Gas Exchange Physiology", questionType: "multiple-choice", examTip: "Transit time: 0.75 sec, oxygenation complete at 0.25 sec. Reserve allows for exercise. ILD shortens effective exchange time." },
  { id: "rrt-aer-024", stem: "What is the role of inhaled epinephrine in respiratory care?", options: ["Potent alpha-1 mediated mucosal vasoconstriction for upper airway edema (croup, post-extubation stridor); also beta-2 bronchodilation", "Only used for cardiac arrest", "Inhaled form is contraindicated", "Used as a mucolytic agent"], correctIndex: 0, rationale: "Inhaled racemic epinephrine (0.5 mL of 2.25% in 3 mL NS) or L-epinephrine causes potent alpha-1 mediated mucosal vasoconstriction, reducing upper airway edema. Primary uses: moderate-severe croup, post-extubation stridor, laryngeal edema. Also provides beta-2 bronchodilation. Effects are temporary (1-2 hours) — monitor for rebound edema.", difficulty: 2, category: "Aerosol & Medication Delivery", topic: "Bronchodilator Therapy", questionType: "multiple-choice", examTip: "Inhaled epinephrine: alpha-1 vasoconstriction for upper airway edema (croup, post-extubation). Temporary effect — monitor for rebound." },
  { id: "rrt-aer-025", stem: "What is the mechanism of action of montelukast (Singulair)?", options: ["Leukotriene receptor antagonist that blocks CysLT1 receptors, reducing airway inflammation and bronchoconstriction", "Beta-2 agonist causing bronchodilation", "Anticholinergic blocking muscarinic receptors", "Mucolytic breaking disulfide bonds"], correctIndex: 0, rationale: "Montelukast blocks cysteinyl leukotriene receptors (CysLT1), reducing bronchoconstriction, mucus production, and eosinophilic inflammation. Oral medication (not inhaled). Used as add-on therapy for asthma (not first-line) and exercise-induced bronchoconstriction. Not a rescue medication. FDA black box warning for neuropsychiatric effects.", difficulty: 2, category: "Aerosol & Medication Delivery", topic: "Bronchodilator Therapy", questionType: "multiple-choice", examTip: "Montelukast: LTRA, oral, add-on for asthma. Not rescue. Not first-line. Black box: neuropsychiatric effects." },
  { id: "rrt-sniv-021", stem: "What are the advantages of NIV over invasive mechanical ventilation in appropriate patients?", options: ["Avoids intubation risks, preserves speech/swallowing, reduces VAP risk, shorter ICU stays, lower mortality in COPD exacerbation", "NIV provides more ventilatory support than invasive ventilation", "NIV is appropriate for all patients with respiratory failure", "NIV has no advantages over intubation"], correctIndex: 0, rationale: "NIV advantages: (1) Avoids intubation complications (laryngeal injury, VAP), (2) Preserves speech, swallowing, and cough, (3) Allows intermittent application, (4) Reduces ICU LOS and mortality (particularly in COPD exacerbation and cardiogenic pulmonary edema), (5) Easier to initiate and discontinue. Limitations: requires cooperative patient, intact airway reflexes, and adequate mask seal.", difficulty: 2, category: "Sleep & Noninvasive Ventilation", topic: "NIV for Acute Respiratory Failure", questionType: "multiple-choice", examTip: "NIV benefits: avoids intubation, preserves function, reduces VAP, less ICU time. Best evidence: COPD exacerbation." },
  { id: "rrt-em-026", stem: "What is the role of capnography in confirming endotracheal tube placement?", options: ["Continuous waveform capnography is the gold standard for confirming and monitoring ETT placement — persistent ETCO2 waveform confirms tracheal intubation", "ETCO2 is unreliable for ETT confirmation", "Auscultation alone is sufficient", "Only chest X-ray can confirm placement"], correctIndex: 0, rationale: "Continuous waveform capnography is the most reliable method to confirm ETT placement (AHA recommendation). A persistent ETCO2 waveform over 6 breaths confirms tracheal intubation. Esophageal intubation shows absent or rapidly declining ETCO2. Capnography also monitors for ETT displacement during transport and procedures. CXR confirms depth (2-4 cm above carina) but not real-time position.", difficulty: 2, category: "Emergency Respiratory Care", topic: "CPR/ACLS Protocols", questionType: "multiple-choice", examTip: "Waveform capnography = gold standard for ETT confirmation. Persistent waveform = tracheal. No waveform = esophageal." },
  { id: "rrt-em-027", stem: "A patient has acute severe asthma with silent chest and is becoming drowsy. SpO2 78%. pH 7.20, PaCO2 60. What should be done?", options: ["Immediate intubation and mechanical ventilation — this is near-fatal asthma with respiratory failure", "Continue nebulized albuterol and observe", "Start BiPAP", "Discharge with oral prednisone"], correctIndex: 0, rationale: "This is near-fatal asthma (status asthmaticus): silent chest (no air movement), drowsiness (CO2 narcosis from PaCO2 60), severe acidosis (pH 7.20), and profound hypoxemia (SpO2 78%). Immediate intubation is required. Use rapid sequence intubation (ketamine is preferred induction agent — bronchodilator properties). Continue aggressive bronchodilator therapy after intubation.", difficulty: 4, category: "Emergency Respiratory Care", topic: "Anaphylaxis Airway Management", questionType: "case-based", examTip: "Near-fatal asthma: silent chest + drowsiness + respiratory acidosis = intubate NOW. Ketamine preferred for induction." },
  { id: "rrt-pa-024", stem: "What is the difference between egophony, bronchophony, and whispered pectoriloquy?", options: ["All are signs of lung consolidation. Egophony: 'E' sounds like 'A'. Bronchophony: spoken words heard clearly. Whispered pectoriloquy: whispered words heard clearly through stethoscope.", "They are all normal findings", "They indicate pneumothorax", "They are signs of pleural effusion only"], correctIndex: 0, rationale: "These vocal resonance findings indicate lung consolidation (pneumonia, atelectasis): Egophony: patient says 'E,' sounds like 'A' through stethoscope (E-to-A change). Bronchophony: spoken words heard clearly over consolidated lung (normally muffled). Whispered pectoriloquy: whispered words heard clearly (normally inaudible). All occur because consolidated lung transmits sound better than air-filled lung.", difficulty: 2, category: "Patient Assessment", topic: "Respiratory Physical Exam", questionType: "multiple-choice", examTip: "Consolidation signs: Egophony (E→A), Bronchophony (clear speech), Whispered pectoriloquy (clear whispers)." },
  { id: "rrt-pa-025", stem: "What is the significance of clubbing of the fingers in respiratory assessment?", options: ["Chronic hypoxemia causing connective tissue proliferation at the nail bed; associated with lung cancer, bronchiectasis, ILD, and cyanotic heart disease", "Normal variant with no clinical significance", "Acute respiratory distress sign", "Associated only with liver disease"], correctIndex: 0, rationale: "Digital clubbing (increased nail bed angle > 180°, loss of Lovibond angle, sponginess of nail bed) indicates chronic tissue hypoxia. Pulmonary causes: lung cancer (most common), bronchiectasis, ILD, lung abscess, CF. Cardiac: cyanotic congenital heart disease. Other: liver cirrhosis, IBD, endocarditis. NOT caused by COPD (commonly tested — COPD alone doesn't cause clubbing).", difficulty: 2, category: "Patient Assessment", topic: "Respiratory Physical Exam", questionType: "multiple-choice", examTip: "Clubbing: chronic hypoxia. Lung cancer, bronchiectasis, ILD, CF, cyanotic heart disease. NOT COPD alone." },
  { id: "rrt-ic-023", stem: "What is the difference between sterilization and high-level disinfection?", options: ["Sterilization destroys ALL microorganisms including spores; HLD destroys all except high numbers of bacterial spores", "They are identical processes", "HLD is more effective than sterilization", "Sterilization only kills bacteria"], correctIndex: 0, rationale: "Sterilization: complete elimination of ALL microorganisms including bacterial spores (achieved by autoclaving 121°C × 15-30 min, ethylene oxide gas, or hydrogen peroxide plasma). HLD: destroys bacteria, mycobacteria, most viruses, and fungi but NOT high numbers of bacterial spores. Spaulding: critical items (sterile tissue) = sterilize. Semi-critical (mucous membranes) = HLD.", difficulty: 2, category: "Infection Control & Equipment", topic: "Equipment Disinfection", questionType: "multiple-choice", examTip: "Sterilization: kills ALL (including spores). HLD: kills most (NOT high-level spores). Critical = sterilize. Semi-critical = HLD." },
  { id: "rrt-ic-024", stem: "What is the recommended approach for respiratory equipment used by patients on contact precautions?", options: ["Dedicate equipment to the patient; if shared, disinfect between patients with hospital-grade disinfectant", "No special precautions needed", "Use the same equipment for all patients", "Sterilize between every use regardless of isolation status"], correctIndex: 0, rationale: "Contact precautions require: (1) Dedicated patient equipment when possible (stethoscope, SPO2 probe, BP cuff, ventilator circuit), (2) If equipment must be shared, clean and disinfect between patients using hospital-grade (EPA-registered) disinfectant with appropriate contact time, (3) Don gloves and gown before entering room, (4) Remove PPE before exiting room.", difficulty: 2, category: "Infection Control & Equipment", topic: "Isolation Precautions", questionType: "multiple-choice", examTip: "Contact precautions: dedicate equipment. If shared: disinfect between patients. Gloves + gown required." },
  { id: "rrt-mv-067", stem: "What is the effect of increasing PEEP on PaO2, PaCO2, and hemodynamics?", options: ["Increases PaO2 (recruitment), minimal effect on PaCO2, may decrease CO (reduced venous return)", "Increases both PaO2 and PaCO2 equally", "Decreases PaO2", "Has no hemodynamic effects"], correctIndex: 0, rationale: "PEEP effects: (1) Oxygenation: increases PaO2 by recruiting atelectatic alveoli and increasing FRC, (2) Ventilation: minimal direct effect on PaCO2 (may slightly increase dead space at very high PEEP), (3) Hemodynamics: may decrease cardiac output by reducing venous return (increased intrathoracic pressure) and increasing RV afterload. Balance oxygenation benefit vs hemodynamic cost.", difficulty: 3, category: "Mechanical Ventilation", topic: "ARDS Ventilation Strategy", questionType: "multiple-choice", examTip: "PEEP: ↑ PaO2 (recruitment), minimal PaCO2 effect, may ↓ CO (hemodynamic cost). Optimal = best O2 with acceptable hemodynamics." },
  { id: "rrt-mv-068", stem: "A patient is on AC/VC with flow trigger sensitivity set at 2 L/min. The ventilator is auto-cycling (triggering without patient effort). What should be done?", options: ["Decrease trigger sensitivity (increase the flow threshold to 3-5 L/min) or switch to pressure triggering", "Increase trigger sensitivity to 1 L/min", "Ignore the auto-cycling", "Increase the tidal volume"], correctIndex: 0, rationale: "Auto-cycling occurs when the trigger sensitivity is too sensitive, causing the ventilator to interpret circuit noise, water condensation, or cardiac oscillations as patient effort. Solution: decrease sensitivity (make it less sensitive) by increasing the flow threshold (e.g., from 2 to 3-5 L/min) or switching to pressure triggering. Also check for circuit leaks or water in the circuit.", difficulty: 3, category: "Mechanical Ventilation", topic: "Ventilator Troubleshooting", questionType: "case-based", examTip: "Auto-cycling: vent triggers without patient effort. Decrease sensitivity (raise threshold). Check for leaks, water." },
  { id: "rrt-abg-041", stem: "A patient with myasthenia gravis in crisis has ABG: pH 7.28, PaCO2 62, HCO3 28, PaO2 55 on room air. NIF is -15 cmH2O. What does this indicate?", options: ["Acute-on-chronic hypoventilation from neuromuscular weakness — the patient needs ventilatory support", "Normal ABG for myasthenia gravis", "Metabolic acidosis only", "Well-compensated chronic disease with no intervention needed"], correctIndex: 0, rationale: "Myasthenic crisis: NIF -15 (weaker than -20 threshold), rising PaCO2 (62), falling pH (7.28), and hypoxemia. The slightly elevated HCO3 (28) suggests some chronic compensation but the acute pH drop indicates deterioration. This patient needs NIV or intubation. The 20/30/40 rule applies: VC < 20 mL/kg, NIF weaker than -30, MEP < 40 = intubate.", difficulty: 4, category: "ABG Interpretation", topic: "acid-base analysis", questionType: "case-based", examTip: "Neuromuscular crisis: weak NIF + rising PaCO2 + falling pH = ventilatory failure. Apply 20/30/40 rule." },
  { id: "rrt-o2-030", stem: "What is the difference between a heated wire circuit and a non-heated wire circuit in humidification?", options: ["Heated wire prevents condensation (rain-out) in the inspiratory limb by maintaining temperature throughout the circuit", "Heated wire circuits are only for neonates", "Non-heated circuits provide better humidification", "There is no difference"], correctIndex: 0, rationale: "Heated wire circuits maintain the gas temperature along the entire inspiratory limb, preventing cooling and condensation (rain-out). Benefits: reduced condensate (aspiration risk), more consistent temperature and humidity delivery, reduced circuit changes. Without heated wire, gas cools as it travels through the circuit, causing water to condense — creating infection risk and occlusion potential.", difficulty: 2, category: "Oxygen Therapy", topic: "Delivery Devices", questionType: "multiple-choice", examTip: "Heated wire circuit: prevents rain-out/condensation. Better humidity delivery. Less infection risk from condensate." },
  { id: "rrt-aw-029", stem: "What is the role of a gum elastic bougie in a 'can't intubate' scenario?", options: ["Serves as a guide through limited glottic view; inserted blindly toward the anterior trachea, confirmed by tracheal clicks, then used to railroad the ETT", "Used to hold the mouth open", "A type of supraglottic airway device", "Used for nasal intubation only"], correctIndex: 0, rationale: "The bougie is a critical tool when direct laryngoscopy provides a Grade III view (only epiglottis visible). The angled tip is directed anteriorly under the epiglottis toward the trachea. Confirmation of tracheal placement: (1) Tracheal ring clicks (clicking sensation as tip passes over cartilaginous rings), (2) Hold-up sign (resistance at ~30 cm when tip reaches carina). Then railroad the ETT over the bougie.", difficulty: 3, category: "Airway Management", topic: "Endotracheal Intubation", questionType: "multiple-choice", examTip: "Bougie: Grade III view rescue. Tracheal ring clicks = confirmed tracheal placement. Hold-up at ~30 cm = at carina." },
  { id: "rrt-cc-032", stem: "What is stress ulcer prophylaxis and why is it included in the VAP/ICU bundle?", options: ["Prevention of GI bleeding with PPIs or H2 blockers in high-risk ICU patients (ventilated > 48h, coagulopathy)", "Antibiotic prophylaxis for surgical infections", "Prophylactic sedation for all ICU patients", "Prevention of urinary tract infections"], correctIndex: 0, rationale: "Stress ulcer prophylaxis prevents GI bleeding in high-risk ICU patients. Indications: mechanical ventilation > 48 hours, coagulopathy, history of GI bleeding, TBI, burns, or high-dose corticosteroids. Agents: PPIs (pantoprazole) or H2 blockers (famotidine). Part of the ABCDEF bundle. Recent data suggests PPI overuse may increase C. difficile risk — weigh risks vs benefits.", difficulty: 2, category: "Critical Care Respiratory Therapy", topic: "Multi-Organ Failure", questionType: "multiple-choice", examTip: "Stress ulcer prophylaxis: ventilated > 48h or coagulopathy. PPI or H2 blocker. C. diff risk with overuse." },
  { id: "rrt-neo-033", stem: "What is the golden minute in neonatal resuscitation?", options: ["The first 60 seconds of life — initial steps (warm, dry, stimulate, assess) and PPV if needed should begin within this time", "The minute after surfactant administration", "The first minute of chest compressions", "Time from cord clamping to first feeding"], correctIndex: 0, rationale: "The 'golden minute' refers to the first 60 seconds of life during which the initial steps of neonatal resuscitation should be completed: provide warmth, position airway, clear secretions if needed, dry, stimulate, and assess HR and breathing. If HR < 100 or absent/gasping respirations after initial steps, positive pressure ventilation should begin by 60 seconds of life.", difficulty: 2, category: "Neonatal & Pediatric Respiratory Care", topic: "Neonatal Resuscitation", questionType: "multiple-choice", examTip: "Golden minute: complete initial NRP steps by 60 seconds. If HR < 100: start PPV by 60 seconds." },
  { id: "rrt-neo-034", stem: "A premature infant on CPAP 6 cmH2O continues to have frequent apneic episodes. What medication should be started?", options: ["Caffeine citrate (loading dose 20 mg/kg, maintenance 5-10 mg/kg/day)", "Albuterol nebulization", "Epinephrine drip", "Dexamethasone"], correctIndex: 0, rationale: "Caffeine citrate is the first-line treatment for apnea of prematurity. Loading dose: 20 mg/kg IV or PO. Maintenance: 5-10 mg/kg/day. Mechanism: stimulates central respiratory drive (adenosine receptor antagonist), increases diaphragmatic contractility, and enhances CO2 sensitivity. Also shown to reduce BPD incidence and improve neurodevelopmental outcomes in extremely preterm infants.", difficulty: 3, category: "Neonatal & Pediatric Respiratory Care", topic: "Neonatal Resuscitation", questionType: "case-based", examTip: "Apnea of prematurity: caffeine citrate. Load 20 mg/kg, maintain 5-10 mg/kg/day. Reduces BPD risk." },
  { id: "rrt-em-028", stem: "What is the initial energy setting for synchronized cardioversion of atrial fibrillation?", options: ["120-200 joules biphasic (or 200J monophasic)", "50 joules", "360 joules", "10 joules"], correctIndex: 0, rationale: "Synchronized cardioversion energy for atrial fibrillation: 120-200J biphasic (or 200J monophasic). For atrial flutter: 50-100J. For SVT: 50-100J. For monomorphic VT: 100J. Always synchronize (shock delivers on R wave to avoid T-wave and VF). For polymorphic VT (unstable): defibrillate (unsynchronized) — cannot sync to irregular rhythm.", difficulty: 3, category: "Emergency Respiratory Care", topic: "CPR/ACLS Protocols", questionType: "multiple-choice", examTip: "Cardioversion energy: A-fib 120-200J, A-flutter 50-100J, SVT 50-100J, mono VT 100J. Always SYNC mode." },
  { id: "rrt-pa-026", stem: "What does a positive Allen test indicate?", options: ["Adequate collateral blood flow through the ulnar artery — safe to perform radial artery puncture", "Arterial occlusion requiring emergency intervention", "Normal venous return", "Positive for carpal tunnel syndrome"], correctIndex: 0, rationale: "Allen test: (1) Patient makes a fist while RT compresses both radial and ulnar arteries, (2) Patient opens hand (palm is blanched), (3) Release ULNAR artery pressure only, (4) Positive test: palm re-pinks within 5-15 seconds = adequate ulnar collateral circulation = safe to perform radial artery puncture. Negative/inconclusive: consider brachial or femoral artery instead.", difficulty: 2, category: "Patient Assessment", topic: "Respiratory Physical Exam", questionType: "multiple-choice", examTip: "Allen test: check ulnar collateral flow before radial ABG. Positive (re-pink ≤ 15 sec) = safe to proceed." },
  { id: "rrt-ic-025", stem: "What ventilator circuit component should be positioned below the patient's airway to prevent aspiration of condensate?", options: ["Water traps (drain collectors) positioned at the lowest point of the circuit", "The humidifier chamber", "The expiratory filter", "The flow sensor"], correctIndex: 0, rationale: "Water traps should be placed at the lowest points of the ventilator circuit (gravity-dependent position) to collect condensate and prevent it from draining toward the patient's airway. Condensate harbors bacteria and can cause aspiration. Empty water traps regularly away from the patient. Never drain condensate back into the humidifier — it is contaminated.", difficulty: 1, category: "Infection Control & Equipment", topic: "VAP Prevention Bundle", questionType: "multiple-choice", examTip: "Water traps: lowest circuit point. Drain AWAY from patient. Never drain back into humidifier (contaminated)." },
  { id: "rrt-mv-069", stem: "What is the concept of 'open lung ventilation'?", options: ["Strategy of recruiting collapsed alveoli and keeping them open with adequate PEEP while avoiding overdistension", "Ventilating with the chest open during surgery", "Using maximum Vt to open all alveoli", "Ventilation without PEEP"], correctIndex: 0, rationale: "Open lung ventilation (OLV) strategy: (1) Recruit collapsed alveoli with recruitment maneuvers, (2) Keep recruited alveoli open with adequate PEEP (above the lower inflection point on the P-V curve), (3) Prevent overdistension with low Vt (< upper inflection point). Goal: minimize atelectrauma (cyclical opening/closing) and volutrauma (overdistension). Used in ARDS management.", difficulty: 4, category: "Mechanical Ventilation", topic: "ARDS Ventilation Strategy", questionType: "multiple-choice", examTip: "Open lung: recruit → keep open with PEEP → avoid overdistension with low Vt. Prevent atelectrauma + volutrauma." },
  { id: "rrt-mv-070", stem: "A ventilated patient on FiO2 0.45 has PaO2 90. The target is to wean FiO2 while maintaining PaO2 ≥ 60. What is the minimum FiO2 to try next?", options: ["Decrease FiO2 by 0.05 to 0.40 and reassess SpO2/ABG in 15-30 minutes", "Decrease FiO2 to 0.21 immediately", "Keep FiO2 unchanged — PaO2 90 is not high enough to wean", "Increase FiO2 for safety margin"], correctIndex: 0, rationale: "FiO2 weaning should be done gradually (typically 0.05 at a time) with reassessment of SpO2 and/or ABG after each change. With PaO2 90 on FiO2 0.45, there is room to decrease. Goal: maintain PaO2 ≥ 60 (SpO2 ≥ 88-92%) on the lowest possible FiO2. Avoid abrupt large decreases which may cause sudden desaturation.", difficulty: 2, category: "Mechanical Ventilation", topic: "Weaning Protocols", questionType: "case-based", examTip: "FiO2 weaning: decrease by 0.05 at a time. Reassess in 15-30 min. Target: PaO2 ≥ 60, SpO2 ≥ 88%. Gradual steps." },
  { id: "rrt-abg-042", stem: "How does temperature correction (alpha-stat vs pH-stat) affect ABG interpretation?", options: ["Alpha-stat: interpret ABG at 37°C regardless of patient temperature (standard method). pH-stat: correct to actual body temperature (used in deep hypothermia).", "They are identical methods", "pH-stat is standard for all patients", "Temperature does not affect ABG results"], correctIndex: 0, rationale: "Alpha-stat (standard): ABG measured and interpreted at 37°C without correction — pH and PaCO2 may not reflect actual values at non-37°C temperatures. pH-stat: ABG values corrected to the patient's actual body temperature — used during deep hypothermic circulatory arrest (cardiac surgery, neonatal cooling). Most ABG analyzers measure at 37°C. For clinical purposes, alpha-stat is standard.", difficulty: 4, category: "ABG Interpretation", topic: "acid-base analysis", questionType: "multiple-choice", examTip: "Alpha-stat (standard): interpret at 37°C. pH-stat: correct to patient's temperature. Used in hypothermic surgery." },
  { id: "rrt-cp-031", stem: "What is the normal intrapulmonary shunt fraction (Qs/Qt) and what causes it to increase?", options: ["Normal 2-5%; increased by atelectasis, pneumonia, ARDS, pulmonary AVM — blood passes through unventilated lung", "Normal 50%; increased by hyperventilation", "Normal 0%; any shunt is abnormal", "Normal 25%; decreased by lung disease"], correctIndex: 0, rationale: "Normal Qs/Qt (shunt fraction): 2-5% (from bronchial and thebesian veins). Pathologic increase occurs when blood passes through unventilated alveoli: atelectasis, pneumonia consolidation, ARDS, pulmonary AVM. True shunt does NOT respond to supplemental oxygen (key distinction from V/Q mismatch which does). Calculated: Qs/Qt = (CcO2 - CaO2) / (CcO2 - CvO2).", difficulty: 4, category: "Cardiopulmonary Physiology", topic: "Ventilation-Perfusion Matching", questionType: "multiple-choice", examTip: "Normal shunt: 2-5%. True shunt doesn't respond to O2. V/Q mismatch DOES respond to O2. Key distinction." },
  { id: "rrt-aer-026", stem: "What is the recommended technique for DPI (dry powder inhaler) use?", options: ["Exhale away from device, place mouthpiece in mouth, inhale FORCEFULLY and DEEPLY, hold breath 10 seconds", "Exhale into the DPI, then inhale slowly", "Shake the DPI vigorously and inhale slowly", "No specific technique required"], correctIndex: 0, rationale: "DPI technique (different from MDI): (1) Load the dose per device instructions, (2) Exhale AWAY from the device (exhaling into it introduces moisture), (3) Seal lips around mouthpiece, (4) Inhale FAST and DEEP (DPIs are breath-actuated and require sufficient inspiratory flow, typically > 30-60 L/min, to deaggregate the powder), (5) Hold breath 10 seconds, (6) If second dose needed, repeat.", difficulty: 2, category: "Aerosol & Medication Delivery", topic: "Dry Powder Inhalers", questionType: "multiple-choice", examTip: "DPI: inhale FAST and DEEP (unlike MDI which is slow). Exhale AWAY from device. No shaking needed." },
  { id: "rrt-sniv-022", stem: "What is adaptive servo-ventilation (ASV) and when is it used?", options: ["Pressure support mode that automatically adjusts to maintain target ventilation, stabilizing breathing in central sleep apnea and complex sleep-disordered breathing", "Standard CPAP at fixed pressure", "Invasive ventilator mode only", "Only used for obesity hypoventilation"], correctIndex: 0, rationale: "ASV automatically adjusts pressure support breath-by-breath to maintain a target percentage of recent minute ventilation (typically 90%). During apneas/hypopneas: increases support. During hyperventilation: decreases support. Used for: treatment-emergent CSA, complex sleep apnea, CSR in HF (only if EF > 45%). CONTRAINDICATED in HFrEF (EF < 45%) per SERVE-HF trial.", difficulty: 4, category: "Sleep & Noninvasive Ventilation", topic: "Home Ventilation", questionType: "multiple-choice", examTip: "ASV: auto-adjusts PS to stabilize breathing. For CSA/complex SDB. CONTRAINDICATED if EF < 45% (SERVE-HF)." },
  { id: "rrt-em-029", stem: "What is the lethal triad in trauma and how does it affect respiratory management?", options: ["Hypothermia, acidosis, and coagulopathy — each worsens the others; correct with warming, ventilation optimization, and blood product resuscitation", "Three types of chest trauma", "Three vital sign abnormalities", "Three radiographic findings"], correctIndex: 0, rationale: "The lethal triad (trauma triad of death): hypothermia + metabolic acidosis + coagulopathy. Each element perpetuates the others in a vicious cycle. Respiratory therapy role: optimize ventilation to address respiratory acidosis, maintain adequate oxygenation, warm inspired gases with heated humidification, and support damage control resuscitation with permissive hypotension and balanced blood product transfusion.", difficulty: 3, category: "Emergency Respiratory Care", topic: "Smoke Inhalation", questionType: "multiple-choice", examTip: "Lethal triad: hypothermia + acidosis + coagulopathy. RT role: optimize ventilation, warm gases, support resuscitation." },
  { id: "rrt-pa-027", stem: "What is the significance of a chest X-ray showing a 'sail sign'?", options: ["Enlarged thymus in a pediatric patient — normal finding in infants, but if massive may suggest thymoma", "Pneumothorax", "Pericardial effusion", "Diaphragmatic hernia"], correctIndex: 0, rationale: "The 'sail sign' on chest X-ray refers to the appearance of the thymus, which appears as a triangular opacity projecting from the mediastinum, resembling a sail. It is a NORMAL finding in infants and young children (< 2-3 years). The thymus can mimic cardiomegaly or mediastinal mass. It should not be confused with pathology. If unusually large in older children, consider thymoma.", difficulty: 2, category: "Patient Assessment", topic: "Chest X-Ray Interpretation", questionType: "multiple-choice", examTip: "Sail sign: normal thymus in infants on CXR. Triangular opacity from mediastinum. Don't confuse with pathology." },
  { id: "rrt-ic-026", stem: "How long should alcohol-based hand sanitizer be rubbed into hands?", options: ["At least 20 seconds until hands are completely dry — do not wipe off or rinse", "5 seconds", "Until visibly wet — then towel dry", "No specific time requirement"], correctIndex: 0, rationale: "Apply alcohol-based hand rub (ABHR) covering all surfaces of hands and fingers, rub for at least 20 seconds until hands are completely dry. Do NOT wipe off on clothing or towels — the antimicrobial action occurs during the drying process. The alcohol must remain in contact with skin for adequate kill time. If hands are visibly soiled, use soap and water instead.", difficulty: 1, category: "Infection Control & Equipment", topic: "Hand Hygiene Protocols", questionType: "multiple-choice", examTip: "ABHR: rub ≥ 20 sec until DRY. Don't wipe off. Visibly soiled hands → soap and water instead." },
  { id: "rrt-cc-033", stem: "What pulmonary artery catheter measurement best reflects left ventricular preload?", options: ["PAWP (pulmonary artery wedge pressure) — when the balloon is inflated, it reflects left atrial pressure and left ventricular end-diastolic pressure", "CVP (central venous pressure)", "Pulmonary artery systolic pressure", "Mean arterial pressure"], correctIndex: 0, rationale: "PAWP (wedge pressure) is measured by inflating the PA catheter balloon, allowing the catheter to 'wedge' in a distal pulmonary artery branch. This position reflects downstream pressure: LA pressure → LVEDP (left ventricular preload). Normal PAWP: 8-12 mmHg. Elevated in: LV failure, mitral stenosis, fluid overload. CVP reflects right heart preload.", difficulty: 3, category: "Critical Care Respiratory Therapy", topic: "Hemodynamic Monitoring", questionType: "multiple-choice", examTip: "PAWP = LV preload (reflects LA pressure). Normal 8-12. CVP = RV preload. Know which reflects which." },
  { id: "rrt-neo-035", stem: "What is retinopathy of prematurity screening criteria?", options: ["Screen all infants born at ≤ 30 weeks GA or ≤ 1500g birth weight, beginning at 31 weeks postmenstrual age or 4 weeks chronological age, whichever is later", "Screen only if supplemental oxygen was used", "No screening is recommended", "Screen all term infants at birth"], correctIndex: 0, rationale: "AAP/AAO guidelines: Screen all infants born ≤ 30 weeks GA or ≤ 1500g BW. Also screen 1500-2000g infants with unstable clinical course. First exam: 31 weeks postmenstrual age or 4 weeks chronological age, whichever is LATER. Follow-up based on findings. Prevention: careful SpO2 targeting (88-95% for preterm infants), avoiding hyperoxia.", difficulty: 3, category: "Neonatal & Pediatric Respiratory Care", topic: "Neonatal Resuscitation", questionType: "multiple-choice", examTip: "ROP screening: ≤ 30 weeks GA or ≤ 1500g. First exam at 31 weeks PMA or 4 weeks age (whichever later)." },
  { id: "rrt-cp-032", stem: "What is the effect of anemia on oxygen delivery?", options: ["Reduces oxygen-carrying capacity (decreased CaO2) despite normal PaO2 and SaO2, decreasing DO2", "No effect on oxygen delivery", "Increases oxygen delivery through compensatory mechanisms", "Only affects CO2 transport"], correctIndex: 0, rationale: "Anemia reduces hemoglobin concentration, directly decreasing CaO2 (since CaO2 = 1.34 × Hb × SaO2 + dissolved O2). PaO2 and SaO2 remain normal (oxygen is less abundant in blood but still properly exchanged). The body compensates by increasing cardiac output, but this has limits. Severe anemia (Hb < 7) critically reduces DO2 and may require transfusion.", difficulty: 2, category: "Cardiopulmonary Physiology", topic: "Oxygen Transport", questionType: "multiple-choice", examTip: "Anemia: PaO2 and SaO2 normal, but CaO2 LOW (less Hb). DO2 decreased. Compensated by increased CO." },
  { id: "rrt-sniv-023", stem: "What is the role of the respiratory therapist in a polysomnography (sleep study)?", options: ["Score respiratory events, monitor patient during study, apply and adjust PAP devices, and report AHI/RDI results", "Only apply electrodes", "No involvement — sleep studies are done by other specialists", "Only interpret results"], correctIndex: 0, rationale: "RTs with registered polysomnographic technologist (RPSGT) or equivalent certification are integral to sleep studies: (1) Apply monitoring equipment (EEG, EOG, EMG, respiratory belts, oximetry, airflow sensors), (2) Monitor patient during overnight study, (3) Perform split-night study (diagnostic + CPAP titration), (4) Score respiratory events (apneas, hypopneas, RERAs), (5) Calculate AHI/RDI, (6) Adjust PAP settings for optimal treatment.", difficulty: 2, category: "Sleep & Noninvasive Ventilation", topic: "CPAP Titration", questionType: "multiple-choice", examTip: "RT role in PSG: apply equipment, monitor, score events, calculate AHI, titrate PAP. RPSGT credential." },
];
